# Problem: Build a centralized HTTP error handling system for FastAPI-style endpoints.
# Instead of duplicating error-response logic in every endpoint, we create a hierarchy
# of typed exceptions, a universal error handler, and a decorator that catches everything.
#
# Approach:
# - Define HTTPError base with status_code, message, error_code, headers
# - Subclass for each HTTP status (400, 401, 403, 404, 409, 422, 500) with defaults
# - ErrorResponseBody (Pydantic) gives a uniform JSON-like response shape
# - error_handler maps exceptions -> ErrorResponseBody, hiding internals for unknown errors
# - safe_endpoint decorator wraps any function in try/except -> ErrorResponseBody on failure
#
# Time complexity: O(1) for error handling; endpoint logic dominates
# Space complexity: O(1) extra per error response
#
# Key steps:
# 1. Implement each error subclass calling super().__init__ with correct defaults
# 2. Implement error_handler: HTTPError -> structured response; other -> generic 500
# 3. Implement require_auth / require_role raising appropriate errors
# 4. Implement safe_endpoint decorator with try/except
# 5. Implement get_user and create_user using safe_endpoint

import time
from typing import Any, Callable
from pydantic import BaseModel, Field


class HTTPError(Exception):
    def __init__(self, message: str, status_code: int = 500,
                 error_code: str | None = None, headers: dict | None = None):
        super().__init__(message)
        self.message = message
        self.status_code = status_code
        self.error_code = error_code or 'UNKNOWN'
        self.headers = headers


class BadRequestError(HTTPError):
    def __init__(self, message: str = 'Bad request'):
        super().__init__(message, status_code=400, error_code='BAD_REQUEST')


class UnauthorizedError(HTTPError):
    def __init__(self, message: str = 'Unauthorized'):
        # Always include WWW-Authenticate header per HTTP 401 spec
        super().__init__(message, status_code=401, error_code='UNAUTHORIZED',
                         headers={'WWW-Authenticate': 'Bearer'})


class ForbiddenError(HTTPError):
    def __init__(self, message: str = 'Forbidden'):
        super().__init__(message, status_code=403, error_code='FORBIDDEN')


class NotFoundError(HTTPError):
    def __init__(self, message: str = 'Not found'):
        super().__init__(message, status_code=404, error_code='NOT_FOUND')


class ConflictError(HTTPError):
    def __init__(self, message: str = 'Conflict'):
        super().__init__(message, status_code=409, error_code='CONFLICT')


class ValidationError(HTTPError):
    def __init__(self, message: str = 'Validation failed', errors: list[dict] | None = None):
        super().__init__(message, status_code=422, error_code='VALIDATION_ERROR')
        self.errors = errors or []  # Field-level error details


class InternalError(HTTPError):
    def __init__(self, message: str = 'Internal server error'):
        super().__init__(message, status_code=500, error_code='INTERNAL_ERROR')


class ErrorResponseBody(BaseModel):
    status_code: int
    error_code: str
    message: str
    errors: list[dict] = []
    timestamp: float = Field(default_factory=time.time)


def error_handler(exc: Exception) -> ErrorResponseBody:
    if isinstance(exc, HTTPError):
        return ErrorResponseBody(
            status_code=exc.status_code,
            error_code=exc.error_code,
            message=exc.message,
            # Only ValidationError carries field-level errors
            errors=getattr(exc, 'errors', []),
        )
    # Never leak internal details for unexpected exceptions
    return ErrorResponseBody(
        status_code=500,
        error_code='INTERNAL_ERROR',
        message='An unexpected error occurred',
    )


def require_auth(token: str | None) -> dict:
    if not token:
        raise UnauthorizedError('Missing authentication token')
    if token == 'expired':
        raise UnauthorizedError('Token has expired')
    if token == 'invalid':
        raise UnauthorizedError('Invalid token')
    return {'user_id': 1, 'token': token}


def require_role(user: dict, required_role: str) -> bool:
    if user.get('role') != required_role:
        raise ForbiddenError(f'Requires {required_role} role')
    return True


def safe_endpoint(func: Callable) -> Callable:
    def wrapper(*args, **kwargs):
        try:
            return func(*args, **kwargs)
        except HTTPError as exc:
            return error_handler(exc)
        except Exception:
            # Wrap unknown errors so internals are never exposed
            return error_handler(InternalError('An unexpected error occurred'))
    return wrapper


@safe_endpoint
def get_user(user_id: int, token: str | None = None) -> dict:
    require_auth(token)
    if user_id == 0:
        raise BadRequestError('Invalid user ID')
    if user_id == 999:
        raise NotFoundError('User not found')
    return {'id': user_id, 'name': 'User'}


@safe_endpoint
def create_user(data: dict, token: str | None = None) -> dict:
    require_auth(token)

    # Collect all field-level validation errors before raising
    field_errors = []
    if not data.get('name'):
        field_errors.append({'field': 'name', 'message': 'Name is required'})
    if not data.get('email') or '@' not in data.get('email', ''):
        field_errors.append({'field': 'email', 'message': 'Valid email is required'})

    if field_errors:
        raise ValidationError('Validation failed', errors=field_errors)

    if data.get('email') == 'taken@test.com':
        raise ConflictError('Email already exists')

    return {'id': 1, **data}
